class CryptoWallet {
    private var privateKey: Data?
    private var publicKey: Data?
    
    init() {
        generateKeyPair()
    }
    
    func generateKeyPair() {
        let keyPair = SecKeyCreateRandomKey([
            kSecAttrKeyType: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits: 256
        ] as [String: Any], nil)
        
        if let key = keyPair {
            let pubKey = SecKeyCopyPublicKey(key)
            let pubKeyData = SecKeyCopyExternalRepresentation(pubKey!, nil)
            publicKey = pubKeyData as Data?
            
            let privKeyData = SecKeyCopyExternalRepresentation(key, nil)
            privateKey = privKeyData as Data?
        }
    }
    
    func signTransaction(transaction: String) -> Data? {
        guard let privateKey = privateKey else { return nil }
        
        let message = Data(transaction.utf8)
        let signature = try? ECDSA.Signature(
            rawRepresentation: SecKeyCreateSignature(
                privateKey,
                .ECDSASignatureDigestX962SHA256,
                message as CFData,
                nil
            ) as Data
        )
        
        return signature?.rawRepresentation
    }
    
    func getPublicKey() -> String? {
        return publicKey?.base64EncodedString()
    }
    
    func getPrivateKey() -> String? {
        return privateKey?.base64EncodedString()
    }
    
    func sendTransaction(amount: Double, toAddress: String) -> Bool {
        guard let signature = signTransaction(transaction: "\(amount) \(toAddress)") else {
            return false
        }
        
        let transactionData = [
            "amount": amount,
            "to": toAddress,
            "signature": signature.base64EncodedString()
        ]
        
        return sendToBlockchain(transactionData: transactionData)
    }
    
    private func sendToBlockchain(transactionData: [String: Any]) -> Bool {
        guard let url = URL(string: "https://api.blockchain.com/transaction") else { return false }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: transactionData)
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let semaphore = DispatchSemaphore(value: 0)
        var success = false
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 {
                success = true
            }
            semaphore.signal()
        }
        
        task.resume()
        semaphore.wait()
        return success
    }
}

